import{_ as o,o as a,c as i,a0 as r}from"./chunks/framework.BjpW4enL.js";const p=JSON.parse('{"title":"NEXUS V4 Survey","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_reports/V4_SURVEY.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_reports/V4_SURVEY.md","lastUpdated":1782593311000}'),l={name:"Z_Archive/wiki_legacy/archive/legacy_reports/V4_SURVEY.md"};function t(d,e,c,s,u,n){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="nexus-v4-survey" tabindex="-1">NEXUS V4 Survey <a class="header-anchor" href="#nexus-v4-survey" aria-label="Permalink to &quot;NEXUS V4 Survey&quot;">​</a></h1><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>Este documento levanta o que &quot;V4&quot; significa hoje no acervo do NEXUS. Ele não define ainda a arquitetura final do V4. Ele existe para separar:</p><ul><li>runtime atual,</li><li>diagnóstico metodológico,</li><li>fronteira de pesquisa,</li><li>e especulação executiva.</li></ul><h2 id="resumo-executivo" tabindex="-1">Resumo executivo <a class="header-anchor" href="#resumo-executivo" aria-label="Permalink to &quot;Resumo executivo&quot;">​</a></h2><p>Hoje, <code>V4</code> aparece no repositório com pelo menos quatro sentidos diferentes:</p><ol><li><code>V4</code> como correção metodológica do limite do NLP sobre código.</li><li><code>V4</code> como transição para representação estrutural via AST/CFG.</li><li><code>V4</code> como hipótese de execução orientada a Program Counter e estado de máquina.</li><li><code>V4</code> como continuação prática do T4 causal/topológico já estabilizado no runtime.</li></ol><p>O problema é que esses sentidos coexistem sem um mapa comum. O resultado é ambiguidade: às vezes <code>V4</code> quer dizer &quot;melhor retrieval de código&quot;; às vezes quer dizer &quot;nova classe de execução neural&quot;.</p><h2 id="o-que-ja-existe-de-fato" tabindex="-1">O que já existe de fato <a class="header-anchor" href="#o-que-ja-existe-de-fato" aria-label="Permalink to &quot;O que já existe de fato&quot;">​</a></h2><h3 id="_1-runtime-topologico-estabilizado" tabindex="-1">1. Runtime topológico estabilizado <a class="header-anchor" href="#_1-runtime-topologico-estabilizado" aria-label="Permalink to &quot;1. Runtime topológico estabilizado&quot;">​</a></h3><p>O que existe hoje no produto é:</p><ul><li>ingestão ampla em T1/T2/T3;</li><li>recuperação por sementes vetoriais;</li><li>expansão pragmática em T4 por <code>links</code> persistidos;</li><li>resposta estruturada em <code>/query</code>, com <code>packs</code> como padrão.</li></ul><p>Isso é evolução do runtime atual, não o <code>V4</code> especulativo de execução.</p><p>Referências:</p><ul><li><a href="/var/home/bruno/NEXUS/docs/CANONICAL_RUNTIME.html">CANONICAL_RUNTIME.md</a></li><li><a href="/var/home/bruno/NEXUS/docs/CANONICAL_T4.html">CANONICAL_T4.md</a></li><li><a href="/var/home/bruno/NEXUS/workspace/HANDOVER_v3.9_to_v4.html">HANDOVER_v3.9_to_v4.md</a></li></ul><h3 id="_2-diagnostico-metodologico-forte" tabindex="-1">2. Diagnóstico metodológico forte <a class="header-anchor" href="#_2-diagnostico-metodologico-forte" aria-label="Permalink to &quot;2. Diagnóstico metodológico forte&quot;">​</a></h3><p>Há um diagnóstico claro de que NLP denso sobre código puro degrada em bases poluídas. Esse ponto está bem estabelecido:</p><ul><li>base limpa performa bem;</li><li>base poluída colapsa;</li><li>T4 amplifica sinal, mas não corrige semente errada.</li></ul><p>Esse é o núcleo metodológico mais sólido do &quot;rumo ao V4&quot;.</p><p>Referências:</p><ul><li><a href="/var/home/bruno/NEXUS/docs/architecture_decisions/METHODOLOGICAL_CORRECTION_V4.html">METHODOLOGICAL_CORRECTION_V4.md</a></li><li><a href="/var/home/bruno/NEXUS/docs/architecture_decisions/TENSOR_FIRST_STRUCTURAL_RAG.html">TENSOR_FIRST_STRUCTURAL_RAG.md</a></li></ul><h3 id="_3-direcao-estrutural-plausivel" tabindex="-1">3. Direção estrutural plausível <a class="header-anchor" href="#_3-direcao-estrutural-plausivel" aria-label="Permalink to &quot;3. Direção estrutural plausível&quot;">​</a></h3><p>Também já existe uma direção tecnicamente plausível e incremental:</p><ul><li>higienização de T1;</li><li>embeddings de código em vez de NLP genérico;</li><li>chunking por AST em vez de string;</li><li>grafos tipados em T4 (<code>calls</code>, <code>imports</code>, <code>implements</code>, etc.).</li></ul><p>Essa linha ainda é prospectiva, mas é compatível com o runtime atual e com o diagnóstico metodológico.</p><p>Referências:</p><ul><li><a href="/var/home/bruno/NEXUS/docs/architecture_decisions/TENSOR_FIRST_STRUCTURAL_RAG.html">TENSOR_FIRST_STRUCTURAL_RAG.md</a></li><li><a href="/var/home/bruno/NEXUS/docs/architecture_decisions/REFATORACAO_MEMORIA_OPERACIONAL.html">REFATORACAO_MEMORIA_OPERACIONAL.md</a></li></ul><h2 id="o-que-existe-como-hipotese-nao-como-plano-operacional" tabindex="-1">O que existe como hipótese, não como plano operacional <a class="header-anchor" href="#o-que-existe-como-hipotese-nao-como-plano-operacional" aria-label="Permalink to &quot;O que existe como hipótese, não como plano operacional&quot;">​</a></h2><h3 id="_1-v4-como-captura-de-program-counter" tabindex="-1">1. V4 como captura de Program Counter <a class="header-anchor" href="#_1-v4-como-captura-de-program-counter" aria-label="Permalink to &quot;1. V4 como captura de Program Counter&quot;">​</a></h3><p>O blueprint de <code>Cortical Stem Cells</code> propõe um salto muito maior:</p><ul><li>capturar PC e registradores;</li><li>fundir AST + estado;</li><li>gerar um &quot;seed tensor&quot;;</li><li>diferenciar kernels CUDA em tempo de execução.</li></ul><p>Isso não é continuação natural do runtime atual. Isso é uma hipótese de nova classe de sistema, próxima de <code>nexus-cortex</code>, não um próximo passo pequeno do NEXUS atual.</p><p>Referência:</p><ul><li><a href="/var/home/bruno/NEXUS/docs/architecture_decisions/V4_CORTICAL_STEM_CELLS.html">V4_CORTICAL_STEM_CELLS.md</a></li></ul><h3 id="_2-v4-como-fork-separado" tabindex="-1">2. V4 como fork separado <a class="header-anchor" href="#_2-v4-como-fork-separado" aria-label="Permalink to &quot;2. V4 como fork separado&quot;">​</a></h3><p>Também aparece no acervo a ideia de que:</p><ul><li>o NEXUS atual permanece como memória/córtex de longo prazo;</li><li>um fork ou repositório irmão assumiria o papel de execução direta.</li></ul><p>Essa formulação pode ser válida, mas hoje é conceito de fronteira, não decisão operacional consolidada no repositório.</p><h2 id="leitura-recomendada-do-v4-hoje" tabindex="-1">Leitura recomendada do V4 hoje <a class="header-anchor" href="#leitura-recomendada-do-v4-hoje" aria-label="Permalink to &quot;Leitura recomendada do V4 hoje&quot;">​</a></h2><p>Se formos disciplinados, a leitura correta é:</p><ol><li><p><code>V4 mínimo plausível</code></p><ul><li>higienização de corpus</li><li>embeddings de código</li><li>chunking estrutural</li><li>grafos tipados</li></ul></li><li><p><code>V4 máximo especulativo</code></p><ul><li>captura de PC</li><li>AST + estado de máquina</li><li>execução neural / stem cells CUDA</li></ul></li></ol><p>Essas duas coisas não devem mais ser tratadas como se fossem o mesmo plano.</p><h2 id="status-por-eixo" tabindex="-1">Status por eixo <a class="header-anchor" href="#status-por-eixo" aria-label="Permalink to &quot;Status por eixo&quot;">​</a></h2><h3 id="eixo-a-runtime-atual" tabindex="-1">Eixo A: Runtime atual <a class="header-anchor" href="#eixo-a-runtime-atual" aria-label="Permalink to &quot;Eixo A: Runtime atual&quot;">​</a></h3><ul><li><code>status</code>: existente</li><li><code>grau de maturidade</code>: operacional</li><li><code>base documental</code>: boa</li></ul><h3 id="eixo-b-correcao-metodologica" tabindex="-1">Eixo B: Correção metodológica <a class="header-anchor" href="#eixo-b-correcao-metodologica" aria-label="Permalink to &quot;Eixo B: Correção metodológica&quot;">​</a></h3><ul><li><code>status</code>: bem formulada</li><li><code>grau de maturidade</code>: diagnóstico forte</li><li><code>base documental</code>: boa</li></ul><h3 id="eixo-c-v4-estrutural-incremental" tabindex="-1">Eixo C: V4 estrutural incremental <a class="header-anchor" href="#eixo-c-v4-estrutural-incremental" aria-label="Permalink to &quot;Eixo C: V4 estrutural incremental&quot;">​</a></h3><ul><li><code>status</code>: parcialmente formulado</li><li><code>grau de maturidade</code>: direção plausível, ainda sem plano consolidado</li><li><code>base documental</code>: suficiente para começar um plano</li></ul><h3 id="eixo-d-v4-pc-state-execution" tabindex="-1">Eixo D: V4 PC/state execution <a class="header-anchor" href="#eixo-d-v4-pc-state-execution" aria-label="Permalink to &quot;Eixo D: V4 PC/state execution&quot;">​</a></h3><ul><li><code>status</code>: hipótese de pesquisa</li><li><code>grau de maturidade</code>: conceitual</li><li><code>base documental</code>: blueprint, não plano de implementação</li></ul><h2 id="lacunas-atuais" tabindex="-1">Lacunas atuais <a class="header-anchor" href="#lacunas-atuais" aria-label="Permalink to &quot;Lacunas atuais&quot;">​</a></h2><ul><li>Não existe um documento que diga explicitamente qual destes sentidos de <code>V4</code> é o alvo do repositório atual.</li><li>Não existe separação formal entre <code>V4 incremental</code> e <code>V4 especulativo</code>.</li><li>Não existe plano consolidado ligando o runtime atual ao <code>V4 estrutural incremental</code>.</li><li>Não existe critério de decisão para saber se <code>V4_CORTICAL_STEM_CELLS</code> é roadmap, fork ou apenas pesquisa.</li></ul><h2 id="proximo-passo-recomendado" tabindex="-1">Próximo passo recomendado <a class="header-anchor" href="#proximo-passo-recomendado" aria-label="Permalink to &quot;Próximo passo recomendado&quot;">​</a></h2><p>Antes de desenhar mais arquitetura, o próximo passo de menor esforço e maior retorno é decidir uma taxonomia explícita:</p><ul><li><code>V4-runtime</code><ul><li>continuação incremental do NEXUS atual</li></ul></li><li><code>V4-structural</code><ul><li>transição para AST/CFG/code embeddings/grafos tipados</li></ul></li><li><code>V4-cortex</code><ul><li>hipótese de execução com PC/state/CUDA</li></ul></li></ul><p>Sem essa separação, <code>V4</code> continua significando coisas demais ao mesmo tempo.</p><h2 id="leituras-de-apoio" tabindex="-1">Leituras de apoio <a class="header-anchor" href="#leituras-de-apoio" aria-label="Permalink to &quot;Leituras de apoio&quot;">​</a></h2><ul><li><a href="/var/home/bruno/NEXUS/docs/CANONICAL_RUNTIME.html">CANONICAL_RUNTIME.md</a></li><li><a href="/var/home/bruno/NEXUS/docs/CANONICAL_T4.html">CANONICAL_T4.md</a></li><li><a href="/var/home/bruno/NEXUS/docs/architecture_decisions/METHODOLOGICAL_CORRECTION_V4.html">METHODOLOGICAL_CORRECTION_V4.md</a></li><li><a href="/var/home/bruno/NEXUS/docs/architecture_decisions/TENSOR_FIRST_STRUCTURAL_RAG.html">TENSOR_FIRST_STRUCTURAL_RAG.md</a></li><li><a href="/var/home/bruno/NEXUS/docs/architecture_decisions/V4_CORTICAL_STEM_CELLS.html">V4_CORTICAL_STEM_CELLS.md</a></li><li><a href="/var/home/bruno/NEXUS/workspace/HANDOVER_v3.9_to_v4.html">HANDOVER_v3.9_to_v4.md</a></li></ul>',59)])])}const h=o(l,[["render",t]]);export{p as __pageData,h as default};
